                <div class="articles-wrap" id="articlesWrap"></div>

                <div class="success-card">
                    <div class="success-icon" id="successIcon"></div>
                    <div class="success-body">
                        <div class="lbl">Self-Resolution Success Rate</div>
                        <div class="success-num"><span id="successCount">0</span>%</div>
                        <div class="success-sub">of issues were resolved without creating a ticket</div>
                        <div class="progress-track">
                            <div class="progress-fill" id="progressFill"></div>
                        </div>
                    </div>
                </div>
            </div>
</div>

    <div class="overlay" id="overlay">
        <div class="modal" id="modalBox"></div>
    </div>
@endsection

@push('scripts')
    <script>
        /* ---------------- ICONS ---------------- */

        const ICONS = {
            leaf: '<svg viewBox="0 0 24 24"><path d="M20 4C11 4 4 11 4 20c9 0 16-7 16-16z"/><path d="M4 20c4-6 8-9 14-13"/></svg>',
            tree: '<svg viewBox="0 0 24 24"><path d="M12 3l5 7h-3l4.5 6H15l3 5H6l3-5H5.5L10 10H7l5-7z"/><path d="M12 21v-4"/></svg>',
            search: '<svg viewBox="0 0 24 24"><circle cx="11" cy="11" r="7"/><path d="M21 21l-4.3-4.3"/></svg>',
            billing: '<svg viewBox="0 0 24 24"><path d="M6 2h12v20l-2.5-1.5L13 22l-1-1.5-1 1.5-2.5-1.5L6 22V2z"/><path d="M9 7h6M9 11h6M9 15h3.5"/></svg>',
            account: '<svg viewBox="0 0 24 24"><circle cx="10" cy="9" r="4"/><path d="M3.5 20c1-3.5 3.6-5.5 6.5-5.5s5.2 1.6 6 4"/><circle cx="18.5" cy="7.5" r="2.4"/><path d="M18.5 4.6v.5M18.5 9.9v.5M20.9 6l-.4.3M16.5 8.7l-.4.3M16.1 6l.4.3M20.5 8.7l.4.3"/></svg>',
            orders: '<svg viewBox="0 0 24 24"><path d="M2 8h11v8H2z"/><path d="M13 11h4l4 3v2h-8z"/><circle cx="6" cy="18.5" r="1.7"/><circle cx="17" cy="18.5" r="1.7"/></svg>',
            returns: '<svg viewBox="0 0 24 24"><path d="M4 9a8 8 0 1 1 1.3 6.4"/><path d="M4 5v4h4"/><path d="M11 10.5v3l2.3 1.3"/></svg>',
            troubleshoot: '<svg viewBox="0 0 24 24"><path d="M14.7 6.3a4 4 0 0 1-5.4 5.4L4 17l3 3 5.3-5.3a4 4 0 0 1 5.4-5.4l-2.6 2.6-2-2z"/></svg>',
            security: '<svg viewBox="0 0 24 24"><path d="M12 3l7 3v6c0 4.5-3 7.5-7 9-4-1.5-7-4.5-7-9V6l7-3z"/><path d="M9 12l2 2 4-4"/></svg>',
            ticket: '<svg viewBox="0 0 24 24"><path d="M3 9a2 2 0 0 0 0 4v3a1 1 0 0 0 1 1h16a1 1 0 0 0 1-1v-3a2 2 0 0 1 0-4V6a1 1 0 0 0-1-1H4a1 1 0 0 0-1 1v3z"/><path d="M10 5v1.5M10 11v2M10 17.5V19"/></svg>',
            check: '<svg viewBox="0 0 24 24"><path d="M4 12l5 5L20 6"/></svg>',
            clock: '<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M12 7v5l3.5 2"/></svg>',
            list: '<svg viewBox="0 0 24 24"><path d="M8 6h13M8 12h13M8 18h13"/><circle cx="3.5" cy="6" r="1"/><circle cx="3.5" cy="12" r="1"/><circle cx="3.5" cy="18" r="1"/></svg>',
            tag: '<svg viewBox="0 0 24 24"><path d="M11 3H4v7l10 10 7-7L11 3z"/><circle cx="7.7" cy="7.7" r="1.3"/></svg>'
        };

        /* ---------------- DATA ---------------- */

        const categories = [
            {
                id: 'billing', icon: 'billing', label: 'Billing and payments',
                intro: "Manage invoices, payment methods, and charges connected to your AmbatuGrow account.",
                items: [
                    "View and download past invoices from Billing History.",
                    "Update your saved card or bank details anytime under Payment Methods.",
                    "Failed payments retry automatically after 24 hours before your access is paused.",
                    "Refunds for overcharges are processed within 3–5 business days.",
                    "Switch between monthly and annual billing from your Subscription page."
                ]
            },
            {
                id: 'account', icon: 'account', label: 'Account setup',
                intro: "Everything you need to get your account configured and ready to use.",
                items: [
                    "Verify your email to unlock full account access.",
                    "Add team members and assign roles from Account → Users.",
                    "Set up two-factor authentication for extra security.",
                    "Customize your notification preferences in Settings.",
                    "Import existing data using the Onboarding Wizard."
                ]
            },
            {
                id: 'orders', icon: 'orders', label: 'Orders and shipping',
                intro: "Track orders, delivery timelines, and shipping options.",
                items: [
                    "Track any order in real time from Orders → Track Shipment.",
                    "Standard delivery takes 3–7 business days depending on location.",
                    "You can change a delivery address before an order is marked 'Processing'.",
                    "Express shipping is available at checkout for eligible items.",
                    "You'll get an SMS and email once your order is out for delivery."
                ]
            },
            {
                id: 'returns', icon: 'returns', label: 'Returns and refunds',
                intro: "Steps and policies for returning items or requesting a refund.",
                items: [
                    "Items can be returned within 14 days of delivery, unused and in original packaging.",
                    "Start a return from Orders → Request Return.",
                    "Refunds are issued to your original payment method within 5–7 business days.",
                    "Damaged or wrong items qualify for a free return label.",
                    "Store credit is available as a faster alternative to a refund."
                ]
            },
            {
                id: 'troubleshoot', icon: 'troubleshoot', label: 'Troubleshooting',
                intro: "Fixes for the most common technical issues reported by users.",
                items: [
                    "Clear your browser cache if pages fail to load correctly.",
                    "App crashes are usually fixed by updating to the latest version.",
                    "Slow performance is often caused by an unstable internet connection — try switching networks.",
                    "If a page shows an error code, note it down before contacting support.",
                    "Log out and back in to refresh a stuck session."
                ]
            },
            {
                id: 'security', icon: 'security', label: 'Security and privacy',
                intro: "How your data is protected and how to manage your privacy settings.",
                items: [
                    "Enable login alerts to get notified of new device sign-ins.",
                    "Your data is encrypted both in transit and at rest.",
                    "Review and revoke connected third-party apps under Privacy → Connections.",
                    "You can request a full export or deletion of your data anytime.",
                    "Suspicious activity automatically locks your account pending verification."
                ]
            },
        ];

        const allTopics = [
            "Resetting your password", "Updating billing information", "Tracking an order",
            "Requesting a refund", "Setting up two-factor authentication", "Changing your email address",
            "Cancelling a subscription", "Adding a team member", "Understanding invoice charges",
            "Fixing app login errors", "Changing delivery address", "Enabling notifications",
            "Exporting your account data", "Reporting a suspicious login", "Connecting third-party apps"
        ];

        const topicDetails = {};
        allTopics.forEach(t => {
            topicDetails[t] = `Heads up: this is a quick overview of "${t}". Generally, you can manage this directly from your account settings or dashboard. If you run into trouble, our support agents are one ticket away and usually respond within a few hours.`;
        });

        const articles = [
            {
                title: "How to reset your password?", desc: "Step-by-step guide to regain account access.",
                steps: [
                    "Go to the login page and click 'Forgot password'.",
                    "Enter the email linked to your account.",
                    "Check your inbox for a reset link (valid for 30 minutes).",
                    "Click the link and enter a new password twice to confirm.",
                    "Log in using your new password — you're all set!"
                ]
            },
            {
                title: "How to update your billing information?", desc: "Change your card or billing address in a few taps.",
                steps: [
                    "Open Account → Billing from the main menu.",
                    "Select 'Payment Methods'.",
                    "Click 'Add new' or edit an existing card.",
                    "Enter your updated card or address details.",
                    "Save changes — your next invoice will use the new info."
                ]
            },
            {
                title: "How to track your order?", desc: "Find out exactly where your package is.",
                steps: [
                    "Go to Orders in your dashboard.",
                    "Select the order you want to track.",
                    "Click 'Track Shipment' to see live courier updates.",
                    "Enable SMS alerts for delivery status changes.",
                    "Contact support if tracking hasn't updated in 48 hours."
                ]
            },
            {
                title: "How to request a refund?", desc: "Start and complete a refund request smoothly.",
                steps: [
                    "Open the order you'd like refunded.",
                    "Click 'Request Return or Refund'.",
                    "Choose a reason and upload photos if the item was damaged.",
                    "Submit the request — you'll get a confirmation email.",
                    "Refunds are processed within 5–7 business days once approved."
                ]
            },
            {
                title: "How to enable two-factor authentication?", desc: "Add an extra layer of security to your account.",
                steps: [
                    "Go to Settings → Security.",
                    "Toggle on 'Two-Factor Authentication'.",
                    "Scan the QR code with an authenticator app.",
                    "Enter the 6-digit code to confirm setup.",
                    "Save your backup codes somewhere safe."
                ]
            },
            {
                title: "How to update your profile information?", desc: "Keep your name, photo, and contact details up to date.",
                steps: [
                    "Go to Settings → Profile.",
                    "Click 'Edit Profile'.",
                    "Update your name, photo, or contact number.",
                    "Click 'Save Changes'.",
                    "Your updated info reflects across your account right away."
                ]
            },
            {
                title: "How to add or remove a payment method?", desc: "Manage the cards and accounts linked to your account.",
                steps: [
                    "Go to Account → Payment Methods.",
                    "Click 'Add Payment Method' to link a new card or account.",
                    "Or click 'Remove' beside an existing one to delete it.",
                    "Set your preferred method as default anytime.",
                    "At least one active payment method is required for paid plans."
                ]
            },
            {
                title: "How to contact customer support?", desc: "Reach a support agent when self-service isn't enough.",
                steps: [
                    "Click 'Ticket Management System' from the sidebar.",
                    "Select 'Create New Ticket'.",
                    "Choose a category and describe your issue.",
                    "Attach screenshots if it helps explain the problem.",
                    "You'll get updates by email until the ticket is resolved."
                ]
            },
            {
                title: "How to apply a promo code?", desc: "Redeem a discount code at checkout.",
                steps: [
                    "Add items to your cart and proceed to checkout.",
                    "Find the 'Promo Code' field above the total.",
                    "Enter your code exactly as given, then click 'Apply'.",
                    "The discount reflects immediately in your order total.",
                    "Only one promo code can be used per order."
                ]
            },
            {
                title: "How to change your password?", desc: "Update your password anytime while logged in.",
                steps: [
                    "Go to Settings → Security.",
                    "Click 'Change Password'.",
                    "Enter your current password to confirm it's you.",
                    "Enter and confirm your new password.",
                    "Save changes — you'll stay logged in on this device."
                ]
            },
        ];

        /* ---------------- STATIC ICON INJECTION ---------------- */

     if (document.getElementById('brandLeaf')) document.getElementById('brandLeaf').innerHTML =
    '<img src="data:image/png;base64," style="height:35px;">';

        if (document.getElementById('sidebarTree')) document.getElementById('sidebarTree').innerHTML =
    '<img src="data:image/png;base64," style="width:90px;">';

    document.getElementById('heroTree').innerHTML =
    '<img src="data:image/png;base64," style="width:90px;">';
        document.getElementById('searchIcon').innerHTML = ICONS.search;
        document.getElementById('successIcon').innerHTML = ICONS.ticket;

        /* ---------------- RENDER ---------------- */

        const categoryGrid = document.getElementById('categoryGrid');
        categories.forEach(cat => {
            const btn = document.createElement('button');
            btn.className = 'topic-card';
            btn.innerHTML = `<span class="icon-badge">${ICONS[cat.icon]}</span><span class="label">${cat.label}</span>`;
            btn.addEventListener('click', () => openCategoryModal(cat));
            categoryGrid.appendChild(btn);
        });

        const articlesWrap = document.getElementById('articlesWrap');
        articles.forEach((a, idx) => {
            const card = document.createElement('div');
            card.className = 'article-card';
            card.style.animationDelay = (0.03 + idx * 0.045) + 's';
            card.innerHTML = `
    <div class="article-main">
      <h4>${a.title}</h4>
      <p>${a.desc}</p>
    </div>
    <div class="article-side">
      <button class="read-more" data-idx="${idx}">Read more <span class="arrow">→</span></button>
      <div class="helpful-row">
        Helpful?
        <button class="fb-btn yes" data-idx="${idx}" data-val="yes">Yes</button>
        <button class="fb-btn no" data-idx="${idx}" data-val="no">No</button>
      </div>
      <div class="fb-thanks" id="thanks-${idx}"></div>
    </div>
  `;
            articlesWrap.appendChild(card);
        });

        articlesWrap.addEventListener('click', (e) => {
            if (e.target.classList.contains('read-more')) {
                const idx = e.target.getAttribute('data-idx');
                openArticleModal(articles[idx]);
            }
            if (e.target.classList.contains('fb-btn')) {
                const idx = e.target.getAttribute('data-idx');
                const val = e.target.getAttribute('data-val');
                const yesBtn = articlesWrap.querySelector(`.fb-btn.yes[data-idx="${idx}"]`);
                const noBtn = articlesWrap.querySelector(`.fb-btn.no[data-idx="${idx}"]`);
                const thanks = document.getElementById(`thanks-${idx}`);
                const alreadyActive = e.target.classList.contains('active');
                yesBtn.classList.remove('active');
                noBtn.classList.remove('active');
                if (!alreadyActive) {
                    e.target.classList.add('active');
                    thanks.textContent = val === 'yes' ? "Thanks for your feedback!" : "Sorry about that — we'll work on improving this.";
                } else {
                    thanks.textContent = '';
                }
            }
        });

        /* ---------------- MODAL ---------------- */

        const overlay = document.getElementById('overlay');
        const modalBox = document.getElementById('modalBox');

        function closeModal() {
            overlay.classList.remove('show');
            modalBox.innerHTML = '';
        }

        overlay.addEventListener('click', (e) => {
            if (e.target === overlay) closeModal();
        });

        function openModal(html) {
            modalBox.innerHTML = html;
            overlay.classList.add('show');
            const closeBtn = modalBox.querySelector('.modal-close');
            if (closeBtn) closeBtn.addEventListener('click', closeModal);
        }

        function openCategoryModal(cat) {
            const list = cat.items.map(i => `
    <div class="info-item">
      <span class="check">${ICONS.check}</span>
      <p>${i}</p>
    </div>`).join('');
            openModal(`
    <div class="modal-head"><h3><span class="modal-head-icon">${ICONS[cat.icon]}</span>${cat.label}</h3><button class="modal-close">✕</button></div>
    <div class="modal-body">
      <div class="modal-lead">${cat.intro}</div>
      <div class="info-eyebrow">Good to know</div>
      <div class="info-list">${list}</div>
    </div>
  `);
        }

        function openTopicModal(topic) {
            openModal(`
    <div class="modal-head"><h3>${topic}</h3><button class="modal-close">✕</button></div>
    <div class="modal-body"><p>${topicDetails[topic]}</p></div>
  `);
        }

        function openArticleModal(article) {
            const steps = article.steps.map((s, i) => `
    <div class="step-item">
      <div class="step-num">${i + 1}</div>
      <div class="step-text">${s}</div>
    </div>
  `).join('');
            const estMinutes = Math.max(1, Math.round(article.steps.length * 0.6));
            openModal(`
    <div class="modal-head"><h3><span class="modal-head-icon">${ICONS.list}</span>${article.title}</h3><button class="modal-close">✕</button></div>
    <div class="modal-body">
      <p>${article.desc}</p>
      <div class="guide-meta">
        <span>${ICONS.list}${article.steps.length} steps</span>
        <span>${ICONS.clock}~${estMinutes} min</span>
      </div>
      <div class="steps-track">${steps}</div>
    </div>
  `);
        }

        document.getElementById('browseAllBtn').addEventListener('click', () => {
            const list = allTopics.map(t => `<div class="topic-list-item" data-topic="${t}">${t} <span>→</span></div>`).join('');
            openModal(`
    <div class="modal-head"><h3>Browse All Topics</h3><button class="modal-close">✕</button></div>
    <div class="modal-body">${list}</div>
  `);
            modalBox.querySelectorAll('.topic-list-item').forEach(el => {
                el.addEventListener('click', () => openTopicModal(el.getAttribute('data-topic')));
            });
        });

        /* ---------------- SEARCH ---------------- */

        function collectResults(q) {
            const query = q.toLowerCase();
            const results = [];
            articles.forEach(a => { if (a.title.toLowerCase().includes(query) || a.desc.toLowerCase().includes(query)) results.push({ type: 'article', data: a }); });
            categories.forEach(c => { if (c.label.toLowerCase().includes(query) || c.items.some(i => i.toLowerCase().includes(query))) results.push({ type: 'category', data: c }); });
            allTopics.forEach(t => { if (t.toLowerCase().includes(query)) results.push({ type: 'topic', data: t }); });
            return results;
        }

        function escapeHtml(str) {
            return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }

        function highlightMatch(text, q) {
            const escText = escapeHtml(text);
            const escQ = escapeHtml(q);
            const idx = escText.toLowerCase().indexOf(escQ.toLowerCase());
            if (idx === -1 || !escQ) return escText;
            return escText.slice(0, idx) + '<mark>' + escText.slice(idx, idx + escQ.length) + '</mark>' + escText.slice(idx + escQ.length);
        }

        function resultLabel(r) {
            return r.type === 'article' ? r.data.title : r.type === 'category' ? r.data.label : r.data;
        }

        function resultTag(r) {
            return r.type === 'article' ? 'Article' : r.type === 'category' ? 'Topic group' : 'Quick topic';
        }

        function resultIcon(r) {
            return r.type === 'category' ? ICONS[r.data.icon] : r.type === 'article' ? ICONS.list : ICONS.tag;
        }

        function openResult(r) {
            if (r.type === 'article') openArticleModal(r.data);
            else if (r.type === 'category') openCategoryModal(r.data);
            else openTopicModal(r.data);
        }

        function runSearch() {
            const q = document.getElementById('searchInput').value.trim();
            if (!q) { return; }
            closeSuggestions();
            const results = collectResults(q);

            if (results.length === 0) {
                openModal(`
      <div class="modal-head"><h3>Search results</h3><button class="modal-close">✕</button></div>
      <div class="modal-body"><p>No matches for "<strong>${escapeHtml(q)}</strong>". Try a different keyword, or browse all topics instead.</p></div>
    `);
                return;
            }

            const list = results.map((r, i) => {
                return `<div class="topic-list-item" data-idx="${i}">${resultLabel(r)} <span style="font-size:11px;color:var(--muted);font-weight:500;">${resultTag(r)}</span></div>`;
            }).join('');

            openModal(`
    <div class="modal-head"><h3>Results for "${escapeHtml(q)}"</h3><button class="modal-close">✕</button></div>
    <div class="modal-body">${list}</div>
  `);

            modalBox.querySelectorAll('.topic-list-item').forEach((el, i) => {
                el.addEventListener('click', () => openResult(results[i]));
            });
        }

        document.getElementById('searchBtn').addEventListener('click', runSearch);

        /* ---------------- LIVE SUGGESTIONS ---------------- */

        const searchInput = document.getElementById('searchInput');
        const suggestionsBox = document.getElementById('searchSuggestions');
        const searchWrap = document.querySelector('.search-wrap');
        let currentSuggestions = [];
        let activeSuggestionIndex = -1;

        function closeSuggestions() {
            suggestionsBox.classList.remove('show');
            suggestionsBox.innerHTML = '';
            currentSuggestions = [];
            activeSuggestionIndex = -1;
        }

        function setActiveSuggestion(idx) {
            const items = suggestionsBox.querySelectorAll('.suggestion-item');
            items.forEach(el => el.classList.remove('active'));
            if (idx >= 0 && items[idx]) {
                items[idx].classList.add('active');
                items[idx].scrollIntoView({ block: 'nearest' });
            }
            activeSuggestionIndex = idx;
        }

        function renderSuggestions(rawQuery) {
            const q = rawQuery.trim();
            if (!q) { closeSuggestions(); return; }

            const results = collectResults(q).slice(0, 7);
            currentSuggestions = results;
            activeSuggestionIndex = -1;

            if (results.length === 0) {
                suggestionsBox.innerHTML = `<div class="suggestion-empty">No quick matches for "${escapeHtml(q)}". Press Enter to search everything.</div>`;
            } else {
                const items = results.map((r, i) => `
      <div class="suggestion-item" data-idx="${i}">
        <span class="suggestion-icon">${resultIcon(r)}</span>
        <span class="suggestion-text"><span class="name">${highlightMatch(resultLabel(r), q)}</span></span>
        <span class="suggestion-tag">${resultTag(r)}</span>
      </div>`).join('');
                suggestionsBox.innerHTML = items + `<div class="suggestion-hint">Press Enter to see all results for "${escapeHtml(q)}"</div>`;
            }

            suggestionsBox.classList.add('show');

            suggestionsBox.querySelectorAll('.suggestion-item').forEach(el => {
                el.addEventListener('mouseenter', () => setActiveSuggestion(parseInt(el.getAttribute('data-idx'), 10)));
                el.addEventListener('click', () => {
                    const idx = parseInt(el.getAttribute('data-idx'), 10);
                    closeSuggestions();
                    openResult(results[idx]);
                });
            });
        }

        searchInput.addEventListener('input', (e) => renderSuggestions(e.target.value));

        searchInput.addEventListener('focus', () => {
            if (searchInput.value.trim()) renderSuggestions(searchInput.value);
        });

        searchInput.addEventListener('keydown', (e) => {
            const count = currentSuggestions.length;
            if (e.key === 'ArrowDown') {
                e.preventDefault();
                if (count > 0) setActiveSuggestion((activeSuggestionIndex + 1) % count);
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                if (count > 0) setActiveSuggestion((activeSuggestionIndex - 1 + count) % count);
            } else if (e.key === 'Enter') {
                if (activeSuggestionIndex >= 0 && currentSuggestions[activeSuggestionIndex]) {
                    const r = currentSuggestions[activeSuggestionIndex];
                    closeSuggestions();
                    openResult(r);
                } else {
                    runSearch();
                }
            } else if (e.key === 'Escape') {
                closeSuggestions();
            }
        });

        document.addEventListener('click', (e) => {
            if (!searchWrap.contains(e.target)) closeSuggestions();
        });

        /* ---------------- SUCCESS RATE ANIMATION ---------------- */

        function animateSuccessRate(target) {
            const countEl = document.getElementById('successCount');
            const fillEl = document.getElementById('progressFill');
            const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
            if (reduce) {
                countEl.textContent = target;
                fillEl.style.width = target + '%';
                return;
            }
            fillEl.style.width = target + '%';
            let current = 0;
            const duration = 1200;
            const start = performance.now();
            function step(ts) {
                const progress = Math.min((ts - start) / duration, 1);
                current = Math.round(progress * target);
                countEl.textContent = current;
                if (progress < 1) requestAnimationFrame(step);
            }
            requestAnimationFrame(step);
        }

        window.addEventListener('load', () => animateSuccessRate(62));

        /* user chip toggle (visual only) */
        const userChip = document.getElementById('userChip');
        if (userChip) {
            userChip.addEventListener('click', function () {
                this.classList.toggle('open');
            });
        }
    </script>
@endpush
